-- =====================================================================
-- Pharma Sales Data (daily), sourced from Kaggle:
-- kaggle.com/datasets/milanzdravkovic/pharma-sales-data
-- Real transactional-style sales data, publicly available for
-- educational/practice use. ATC codes are the standard international
-- drug classification system.
-- =====================================================================

CREATE TABLE PharmaSalesDaily (
    SaleDate DATE,
    M01AB DECIMAL(10,2),   -- Anti-inflammatory/antirheumatic (non-steroidal)
    M01AE DECIMAL(10,2),   -- Anti-inflammatory/antirheumatic (propionic acid derivatives)
    N02BA DECIMAL(10,2),   -- Analgesics (salicylic acid derivatives)
    N02BE DECIMAL(10,2),   -- Analgesics (pyrazolones/anilides, e.g. paracetamol-type)
    N05B  DECIMAL(10,2),   -- Anxiolytics
    N05C  DECIMAL(10,2),   -- Hypnotics/sedatives
    R03   DECIMAL(10,2),   -- Drugs for obstructive airway diseases (respiratory)
    R06   DECIMAL(10,2),   -- Antihistamines (systemic)
    SalesYear INT,
    SalesMonth INT,
    WeekdayName VARCHAR(15)
);

-- Control table for incremental (watermark-based) loading, based on date
CREATE TABLE LoadControl (
    TableName VARCHAR(100) PRIMARY KEY,
    LastLoadedDate DATE
);






